   isFiltering = true;
   renderCurrentView();
 };

+window.__termwebEsc = function() {
+  // Esc only works on detail pages (not main)
+  if (currentView === 'main') return;
+  if (isFiltering) {
+    isFiltering = false;
+    renderCurrentView();
+  } else {
+    hideDetailView();
+  }
+};
